"""
MKT Christ Layer — Proverbs chapters 28–30
Run: python3 scripts/zc-christ-proverbs-28-30.py

Ch28: Confession-mercy (28:13 → 1 John 1:9); righteous bold as lion (28:1);
      Christ as the one who never conceals — the one whose open righteousness anchors bold confidence
Ch29: Prophetic vision restored (29:18 → John 1:14); humble honored (29:23 → Phil 2:8-9);
      fear of man vs. fear of God (29:25); king judges poor → eternal throne (29:14 → Luke 1:32)
Ch30: Agur's unanswerable questions about the divine Son (30:4 → John 3:13);
      every word of God proves true (30:5); daily bread (30:8-9 → Matt 6:11);
      small-and-wise creatures; numerical sayings
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "28": {
    "1": "<p><b>Theme.</b> <em>The wicked flee when no one pursues, but the righteous are bold as a lion</em> — the lion-boldness of the righteous is grounded in their clear conscience before God. Christ is the lion of the tribe of Judah (Rev 5:5) who advanced toward the cross without flinching — the maximum embodiment of this proverb's lion-boldness. Those united to him share in his boldness: <em>let us then with confidence draw near to the throne of grace</em> (Heb 4:16). The bold confidence is not self-generated but participatory — the righteous are bold as the lion because they stand in the Lion.</p>",
    "2": "<p><b>Revelation of God.</b> <em>When a land transgresses, it has many rulers, but with a man of understanding and knowledge, stability endures</em> — the man of understanding who sustains stability amid national transgression. Christ is the one in whom both understanding and knowledge are hidden (Col 2:3), whose reign provides the stability that no political arrangement can produce. His eternal kingdom does not cycle through the coups and short reigns that national sin produces — the land where his rule is acknowledged has the stability that a thousand human counselors cannot secure.</p>",
    "3": "<p><b>Revelation of God.</b> <em>A poor man who oppresses the poor is like a driving rain that leaves no food</em> — exploitation within vulnerability as destruction rather than nourishment. Christ identifies with the poor (Matt 8:20; 2 Cor 8:9) and forbids the exploitation of the weak. His parable of the unmerciful servant (Matt 18:23-35) is the NT narrative of this proverb: the servant forgiven an enormous debt then squeezes a fellow servant is the poor-man-oppressing-poor — and the judgment falls accordingly. Christ calls his people to be the rain that nourishes rather than destroys.</p>",
    "4": "<p><b>Theme.</b> <em>Those who forsake the law praise the wicked, but those who keep the law strive against them</em> — moral alignment produces social alliance. Christ's own ministry created this dynamic: those who kept the law's spirit (the poor, tax collectors, prostitutes) were drawn to him; those who praised the wicked (collaborating with Rome, exploiting the temple economy) set themselves against him. John 3:20-21: <em>everyone who does wicked things hates the light... but whoever does what is true comes to the light</em> — the alignment the proverb observes.</p>",
    "5": "<p><b>Revelation of God.</b> <em>Evil men do not understand justice, but those who seek the LORD understand it fully</em> — justice-perception conditioned by God-seeking. John 8:43: <em>why do you not understand what I say? It is because you cannot bear to hear my word</em>. The inability to understand justice is not intellectual limitation but moral closure — the Pharisees cannot perceive Christ's justice because their seeking is misdirected. Those who seek the Father find that Christ himself is the one the Father seeks to reveal (John 6:37, 44), and in finding him they find the source of all justice.</p>",
    "6": "<p><b>Type.</b> <em>Better a poor man who walks in integrity than a rich man who is crooked in his ways</em> — the better-than of honest poverty over wealthy corruption. Christ, though rich, became poor (2 Cor 8:9) — and walked in integrity throughout his earthly life. The incarnation is the maximum version of this proverb's preference: the one who possessed all things chose the poor man's path so that those impoverished by sin might become rich in him. His poverty was the integrity that purchased what no corrupt wealth could buy.</p>",
    "7": "<p><b>Theme.</b> <em>The one who keeps the law is a son who makes a glad father, but a companion of gluttons shames his father</em> — the law-keeping son as the father's joy. Christ is the Son who perfectly kept the law (Matt 5:17; Gal 4:4) and in whom the Father found complete delight (Matt 3:17). Those who are adopted into sonship through Christ participate in this law-keeping through the Spirit (Rom 8:4) and become sons who make the Father glad — not through their own achievement but through union with the Son who fulfilled the law in their place.</p>",
    "8": "<p><b>Theme.</b> <em>Whoever multiplies his wealth by interest from the poor will gather it for him who is generous to the poor</em> — the providential redistribution of extracted wealth to the generous. The Zacchaeus episode (Luke 19:1-10) is the narrative form of this redistribution: the tax collector who had extracted from the poor encounters Christ and immediately pledges to give half his goods to the poor and restore fourfold what he had taken. The meeting with Christ triggered the redistribution Proverbs prophesies — the wealth gathered from the poor returned to the poor through the generous response that Christ's presence evokes.</p>",
    "9": "<p><b>Revelation of God.</b> <em>If one turns away his ear from hearing the law, even his prayer is an abomination</em> — ritual prayer without ethical responsiveness is rejected by God. Christ develops this into the parable of the Pharisee and tax collector (Luke 18:9-14): the Pharisee's prayer is the abomination of the one who hears the law without moral transformation; the tax collector's prayer is the prayer of the one who has heard the law's verdict and responds with genuine contrition. The accepted prayer is not the lengthy one but the honest one from the person who has not turned away from what the law reveals.</p>",
    "10": "<p><b>Theme.</b> <em>Whoever misleads the upright into an evil way will fall into his own pit, but the blameless will have a goodly inheritance</em> — the self-made pit. Christ's woes against those who mislead (Matt 23:13-15: <em>woe to you scribes and Pharisees, for you shut the kingdom of heaven in people's faces</em>) are the most direct NT expression of this verdict: those who mislead the upright fall into the pit they dug. The blameless who inherit good are those whose path was not deflected by the misleaders — whose inheritance is the kingdom secured through Christ's blameless life.</p>",
    "11": "<p><b>Theme.</b> <em>A rich man is wise in his own eyes, but a poor man who has understanding sees through him</em> — wealth-generated self-opinion punctured by wisdom. The disciples were predominantly from the poor and laboring class — fishermen, tax collectors — whose lack of social position gave them the perceptive capacity to see through the wisdom-pretense of the wealthy. Christ explicitly thanks the Father for hiding things from the wise and learned and revealing them to little children (Matt 11:25-26). The poverty of spirit (Matt 5:3) that produces the capacity to see truly is the beatitude form of this proverb.</p>",
    "12": "<p><b>Theme.</b> <em>When the righteous triumph, there is great glory; but when the wicked rise, people hide themselves</em> — the social barometer. The resurrection is the triumph of the righteous — the great glory of Easter morning: <em>why do you seek the living among the dead?</em> (Luke 24:5). When Christ is lifted up (John 12:32), he draws all people to himself rather than making them hide. The contrast with the wicked's rise — under which people hide — maps precisely onto the eschatological contrast between Christ's reign and the beast-empires of Revelation under which the inhabitants of the earth hide in caves (Rev 6:15-16).</p>",
    "13": "<p><b>Direct.</b> <em>Whoever conceals his transgressions will not prosper, but he who confesses and forsakes them will obtain mercy</em> — the two-movement pattern of confession and abandonment that leads to mercy. John's formulation is the NT form: <em>if we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness</em> (1 John 1:9). The mercy promised in Proverbs is now grounded specifically in Christ's atoning work — the faithful-and-just forgiveness is possible because Christ bore the sin that was confessed. The concealing that prevents prosperity is the refusal of the cross's offer: acknowledgment of need as the condition of receiving grace.</p>",
    "14": "<p><b>Theme.</b> <em>Blessed is the one who fears the LORD always, but whoever hardens his heart will fall into calamity</em> — the beatitude form for the continuously God-fearing. Hebrews develops the hardened heart warning extensively (Heb 3:7-15; 4:7, citing Ps 95): <em>today, if you hear his voice, do not harden your hearts</em>. The hardening is a specific refusal of Christ's voice — the one speaking is greater than Moses (Heb 3:3), and to harden against him is to forfeit the rest that remains (Heb 4:9-11). The fear of the LORD that the proverb pronounces blessed is realized in the one who receives Christ's word with softened receptivity.</p>",
    "15": "<p><b>Type.</b> <em>Like a roaring lion or a charging bear is a wicked ruler over a poor people</em> — the predator-king as the antithesis of the shepherd-king. Daniel's vision of world empires as beasts (Dan 7:3-7) uses precisely the lion and bear imagery for kingdoms that devour their people. Christ presents himself as the good shepherd — not the predator but the one who lays down his life for the sheep (John 10:11). The lion-and-bear predators of Proverbs anticipate the beast-empires of Daniel and Revelation; the shepherd-king who comes is the countertype who ends the predator's reign.</p>",
    "16": "<p><b>Revelation of God.</b> <em>A ruler who lacks understanding is a cruel oppressor, but he who hates unjust gain will prolong his days</em> — understanding as the alternative to cruelty. Christ's governance is characterized by understanding in the fullest sense: <em>he knows what is in man</em> (John 2:25); he understands the people he leads without needing anyone to inform him. His reign prolongs not merely days but eternity — the throne upheld by faithful justice (Prov 29:14; Luke 1:32-33) is the ruler-who-hates-unjust-gain carried to its eschatological fulfillment in the king whose kingdom has no end.</p>",
    "17": "<p><b>Theme.</b> <em>If one is burdened with the blood of another, he will flee until death</em> — the bloodguilt that pursues without relief. Christ is the cities of refuge in person: <em>come to me, all who labor and are heavy laden, and I will give you rest</em> (Matt 11:28). The one burdened with blood can flee to Christ and find the relief the cities of refuge provided to the accidental killer — but with a deeper resolution: the blood-burden is not merely managed but taken away, because Christ's blood speaks a better word than the blood of Abel (Heb 12:24), covering rather than crying out for vengeance.</p>",
    "18": "<p><b>Theme.</b> <em>Whoever walks in integrity will be delivered, but he who is crooked in his ways will suddenly fall</em> — integrity as deliverance. Christ walked in complete integrity through every temptation (Heb 4:15) and his walking-in-integrity was the path that led through death to resurrection — the ultimate deliverance. Those united to him are reckoned as walking in integrity (Rom 8:1: <em>no condemnation for those who are in Christ Jesus</em>) — their deliverance is his integrity credited to them. The sudden fall of the crooked is the collapse of the self-constructed duplicity that cannot sustain itself under God's scrutiny.</p>",
    "19": "<p><b>Theme.</b> <em>Whoever works his land will have plenty of bread, but he who follows worthless pursuits will have plenty of poverty</em> — the labor-bread / empty-pursuit-poverty contrast. Christ's instruction about work in the kingdom follows the same pattern: <em>do not work for the food that perishes, but for the food that endures to eternal life</em> (John 6:27). The worthless pursuits are those aimed at the perishing food; the land-working of the kingdom is the labor directed toward eternal outcomes. The bread that results from proper kingdom-labor is ultimately Christ himself (John 6:35) — the bread of life that satisfies every hunger.</p>",
    "20": "<p><b>Theme.</b> <em>A faithful man will abound with blessings, but whoever hastens to be rich will not go unpunished</em> — faithfulness as the route to abundance. The parable of the talents ends with exactly this formula: <em>well done, good and faithful servant... enter into the joy of your master</em> (Matt 25:21) — the faithful man who abounds with blessings. The one who buries his talent to avoid risk is the one who hastens away from risk and loses everything. Christ's own faithfulness to the Father through suffering is the model of the faithful man — the blessings he receives through resurrection are the abound-with-blessings the proverb promises.</p>",
    "21": "<p><b>Revelation of God.</b> <em>To show partiality is not good, yet for a piece of bread a man will do wrong</em> — the cheapness of corruption. Christ's parable of the unjust judge (Luke 18:1-8) contrasts the corrupt judge who finally acts not from justice but from inconvenience with the God who will vindicate his elect. The piece-of-bread corruption is the mundane reality Christ acknowledges — which is why he instructs his disciples to persist in prayer to the God whose justice is not for sale. The divine judge who shows no partiality (Acts 10:34; Rom 2:11) is the countertype to the proverb's corrupt partial judge.</p>",
    "22": "<p><b>Theme.</b> <em>A stingy man hastens after wealth and does not know that poverty will come upon him</em> — the stingy-man's self-defeating poverty. The rich young ruler (Matt 19:16-22) is the narrative embodiment: he hastened after wealth and kept it, and departed poor — lacking the one thing he needed. Christ's invitation (<em>go, sell all you have and give to the poor, and you will have treasure in heaven</em>) is the antidote to the stingy man's unknowing poverty: the trading of temporal accumulation for the wealth that does not fail.</p>",
    "23": "<p><b>Theme.</b> <em>Whoever rebukes a man will afterward find more favor than he who flatters with his tongue</em> — honest rebuke as a form of love. Christ's rebukes — Peter (<em>get behind me, Satan</em>, Matt 16:23), the seven churches (Rev 2-3), the Pharisees (Matt 23) — are the maximum expression of this proverb's principle. The favor afterward is not always immediate but is real: Peter's rebuke led to his transformation into the rock on which the church was built. Paul's instruction that those who love the truth are those who receive rebuke (2 Tim 4:2-3) extends the Christ-pattern to the apostolic ministry.</p>",
    "24": "<p><b>Theme.</b> <em>Whoever robs his father or his mother and says, 'That is no transgression,' is a companion to a man who destroys</em> — self-declared innocence masking violation. Christ's condemnation of Corban (Mark 7:9-13) is the precise NT case: those who used a religious formula to justify withholding resources from their parents were robbing father and mother under cover of piety. Jesus identifies this as making void the word of God for the sake of tradition — the companion-to-a-destroyer verdict. The self-exonerating religious justification is exactly the <em>no transgression</em> the proverb condemns.</p>",
    "25": "<p><b>Direct.</b> <em>A greedy man stirs up strife, but whoever trusts in the LORD will be enriched</em> — trust in the LORD as the alternative to greedy grasping. Christ's instruction on anxiety and provision in the Sermon on the Mount (Matt 6:25-34) identifies trust-in-the-Father as the antidote to the anxious accumulation that produces strife. The enrichment that comes from trusting the LORD is the added things promised to those who seek the kingdom first (Matt 6:33). Those in Christ have the model and the power of this trust — he who did not spare his own Son will also with him graciously give us all things (Rom 8:32).</p>",
    "26": "<p><b>Theme.</b> <em>Whoever trusts in his own mind is a fool, but he who walks in wisdom will be delivered</em> — self-trust vs. wisdom-walking as the path of deliverance. Christ's words are the wisdom in which walking produces deliverance: <em>everyone who hears these words of mine and does them will be like a wise man who built his house on the rock</em> (Matt 7:24). The fool who trusts his own mind is the one who built on sand — whose self-constructed wisdom collapsed. The walking in wisdom is not philosophical but relational: abiding in Christ, the one in whom all wisdom is hidden (Col 2:3).</p>",
    "27": "<p><b>Revelation of God.</b> <em>Whoever gives to the poor will not lack, and he who hides his eyes from the poor will get many a curse</em> — the giving-guarantees-sufficiency principle. The Macedonian churches gave out of extreme poverty to the collection for the Jerusalem poor (2 Cor 8:1-5) — the proverb's promise enacted in apostolic history. Christ's beatitude: <em>blessed are the merciful, for they shall receive mercy</em> (Matt 5:7). The hiding-of-eyes that brings curses is the refusal of the image-of-God in the poor person — a refusal that ultimately is a refusal of the one who became poor for us (2 Cor 8:9).</p>",
    "28": "<p><b>Theme.</b> <em>When the wicked rise, people hide themselves, but when they perish, the righteous increase</em> — the triumph-of-righteousness demographic. The resurrection and Pentecost together are the event in which the wicked who crucified Christ are judged (Acts 2:36-38) and the righteous increase dramatically — three thousand in one day. The pattern of the righteous increasing when the wicked perish is the Acts narrative at its most concentrated: the defeat of sin and death in the resurrection is precisely the moment when the number of disciples begins its multiplication (Acts 2:41, 47).</p>"
  },
  "29": {
    "1": "<p><b>Theme.</b> <em>He who is often reproved yet stiffens his neck will suddenly be broken beyond healing</em> — the accumulated-reproof-ignored pattern ending in irreversible rupture. Hebrews 6:4-6 describes the same irreversibility for those who have received the Spirit and then turned away. The stiffened neck before Christ's ongoing call is the maximum form of this hardening. Matthew 23:37-38: <em>O Jerusalem, Jerusalem... how often would I have gathered your children... Behold, your house is left to you desolate</em> — the repeated reproof, the stiffened neck, the sudden breaking.</p>",
    "2": "<p><b>Theme.</b> <em>When the righteous increase, the people rejoice, but when the wicked rule, the people groan</em> — the governance-affect barometer. Romans 8:22-23: the whole creation groans under the rule of corruption, waiting for the revealing of the sons of God. When Christ's reign is fully established, the groaning ends and the rejoicing begins — the eschatological form of the proverb's social observation. Acts 2-6 already shows the pattern: as the righteous community grew, there was gladness and favor with all the people (Acts 2:46-47).</p>",
    "3": "<p><b>Theme.</b> <em>He who loves wisdom makes his father glad, but a companion of prostitutes squanders his wealth</em> — the father-gladness of wisdom-love. The prodigal son's return is the narrative reversal of the squandering: <em>when he was yet a great way off, his father saw him and had compassion, and ran and fell on his neck</em> (Luke 15:20). The father's running-joy at the returning son is the maximum expression of the father-made-glad by the wisdom of turning back. Christ tells the parable to explain his own practice of welcoming sinners — he is the one who rejoices over each returning companion of the wrong crowd.</p>",
    "4": "<p><b>Type.</b> <em>By justice a king establishes the land, but he who exacts gifts tears it down</em> — justice as the foundation of the kingdom. Christ's eschatological judgment is characterized precisely by justice: <em>in righteousness he judges and makes war</em> (Rev 19:11). The king who establishes land through justice is the type of the one whose kingdom is built on the foundation of justice and righteousness (Isa 9:7) — the same foundation God himself occupies (Ps 89:14). The gift-extorting king who tears down anticipates the beast-kings whose kingdoms are built on extraction and whose collapse is celebrated in Revelation 18-19.</p>",
    "5": "<p><b>Revelation of God.</b> <em>A man who flatters his neighbor spreads a net for his feet</em> — flattery as a trap. Judas's <em>Rabbi</em> and kiss at the moment of betrayal (Matt 26:49) is the ultimate flattery-as-trap: the surface warmth concealing the net. Christ himself warned against smooth-speaking false prophets (Matt 7:15: <em>they come to you in sheep's clothing</em>) and the crowds who praised him on Palm Sunday but called for his crucifixion five days later. The proverb's trap-through-flattery is a pattern Christ encountered throughout his ministry — he could not trust himself to the crowds because he knew what was in man (John 2:24).</p>",
    "6": "<p><b>Theme.</b> <em>An evil man is ensnared in his transgression, but a righteous man sings and rejoices</em> — transgression as self-constructed trap, righteousness as freedom for joy. Christ's interior freedom during his passion is the maximum display of the righteous man's singing-and-rejoicing: <em>for the joy set before him he endured the cross</em> (Heb 12:2). The one who is ensnared in transgression cannot approach the cross with joy; the one whose righteousness is clear sings even in the darkest moment. The disciples' post-resurrection joy (Luke 24:52-53: <em>they returned to Jerusalem with great joy and were continually in the temple blessing God</em>) is the communal form.</p>",
    "7": "<p><b>Theme.</b> <em>A righteous man knows the rights of the poor; a wicked man does not understand such knowledge</em> — knowing the poor's cause as the mark of righteousness. Christ's mission-statement in Luke 4:18 is precisely the knowledge of the poor's cause in action: <em>to proclaim good news to the poor... to set at liberty those who are oppressed</em>. The deliberate cognitive closure of the wicked — <em>does not care to understand</em> (lo yavin) — is the hardened heart Christ describes as unable to perceive the kingdom (John 12:40, citing Isa 6:10). The righteous who knows is the disciple who follows Christ's own attentiveness to the poor.</p>",
    "8": "<p><b>Theme.</b> <em>Scoffers set a city aflame, but wise men turn away wrath</em> — wisdom as de-escalation. Christ is the peacemaker above all — <em>blessed are the peacemakers, for they shall be called sons of God</em> (Matt 5:9). His entry into Jerusalem is the peace-king's entry (Matt 21:5, citing Zech 9:9: <em>your king is coming to you, humble and mounted on a donkey</em>). The scoffers who inflame the city contrast with the one who wept over it (Luke 19:41) and who turned away the wrath that Jerusalem's rebellion was earning — temporarily. The final turning away of wrath is the intercession that flows from Calvary.</p>",
    "9": "<p><b>Theme.</b> <em>If a wise man has an argument with a fool, the fool only rages and laughs, and there is no quiet</em> — the communication-gap between wisdom and folly. Christ before Herod (Luke 23:8-11): Herod questioned him at length but received no response; Herod and his soldiers mocked and treated him with contempt. The wise man who faces the raging-and-laughing fool is Christ at his trials — maintaining silence and dignity while the fool exhausts himself in rage and mockery. John 8:43-47 also: the inability of his opponents to hear his words is not intellectual but moral — they cannot hear because they are of their father the devil.</p>",
    "10": "<p><b>Type.</b> <em>Bloodthirsty men hate one who is blameless and seek the life of the upright</em> — the persecution of the blameless by the bloodthirsty. The chief priests and Pharisees who sought to kill Jesus (John 11:53: <em>from that day on they made plans to put him to death</em>) are the bloodthirsty men of this proverb seeking the life of the perfectly upright one. The Servant of Isaiah who was led to slaughter (Isa 53:7) is also the blameless one whom the bloodthirsty surrounded. Christ's experience is the paradigm; his followers participate in the same pattern (John 15:18-20: <em>if the world hated me, it will also hate you</em>).</p>",
    "11": "<p><b>Theme.</b> <em>A fool gives full vent to his spirit, but a wise man quietly holds it back</em> — the restraint of the wise. Christ before his accusers: <em>he opened not his mouth</em> (Isa 53:7, cited by Philip in Acts 8:32-33). Matthew 27:12-14: when accused, he gave no answer. The wise man's holding-back of his spirit is not weakness but the most powerful form of restraint — the one who could have summoned twelve legions of angels (Matt 26:53) chose the quiet holding-back of his spirit. James 1:19 makes this the apostolic standard: <em>let every person be quick to hear, slow to speak, slow to anger</em>.</p>",
    "12": "<p><b>Revelation of God.</b> <em>If a ruler listens to falsehood, all his officials will be wicked</em> — the cascading moral effect of a leader's credulity. Pilate listened to the falsehood of the accusers (Luke 23:23-24) and his official act of condemnation followed. The entire machinery of the trial was the systemic corruption this proverb describes: one official's decision to entertain false accusations produced the judicial murder of the innocent. But Christ's willingness to submit to this system was not its validation — his resurrection exposed the falsehood and reversed the verdict, demonstrating that the ruler who listens to falsehood does not have the final word.</p>",
    "13": "<p><b>Revelation of God.</b> <em>The poor man and the oppressor meet together; the LORD gives light to the eyes of both</em> — shared creaturely dependence before God. The incarnation is the meeting of the divine with the poorest human condition: <em>though he was rich, yet for your sake he became poor</em> (2 Cor 8:9). At the cross, both oppressor and oppressed are present — the poor disciples, the centurion, the crowd. The light given to both is the light of the cross: <em>and I, when I am lifted up from the earth, will draw all people to myself</em> (John 12:32). Both the poor and their oppressors are summoned to the same light and offered the same mercy.</p>",
    "14": "<p><b>Direct / Type.</b> <em>A king who faithfully judges the poor — his throne will be established forever</em> — the permanent throne grounded in justice for the poor. Luke 1:32-33: <em>he will be great and will be called the Son of the Most High. And the Lord God will give to him the throne of his father David, and he will reign over the house of Jacob forever, and of his kingdom there will be no end</em>. Christ is the king whose throne is established forever precisely because he judges faithfully on behalf of the poor. Luke 4:18 is his manifesto; Revelation 21:3-5 is the throne's eternal establishment. The proverb's conditional (<em>a king who judges... his throne will stand</em>) finds its unconditional fulfillment in the one who judged with perfect faithfulness.</p>",
    "15": "<p><b>Theme.</b> <em>The rod and reproof give wisdom, but a child left to himself brings shame to his mother</em> — discipline as wisdom-formation. Hebrews 12:5-11: the Father's discipline of his children through suffering is the NT form of rod-and-reproof. Christ <em>learned obedience through what he suffered</em> (Heb 5:8) — even the perfectly obedient Son underwent the discipline of the incarnational path. Those united to him undergo the Father's discipline not as punishment but as the formation of the wise child: <em>he disciplines us for our good, that we may share his holiness</em> (Heb 12:10).</p>",
    "16": "<p><b>Theme.</b> <em>When the wicked increase, transgression increases, but the righteous will look upon their downfall</em> — the vindicated-righteous watching the wicked collapse. Revelation 18-19: the righteous (the saints, apostles, and prophets) are called to rejoice at Babylon's fall (Rev 18:20). This is not vengeance but vindication — the moment when the long predominance of wickedness ends. The righteous will look upon their downfall is the prophetic confidence that sustains the community under pressure: the present triumph of the wicked is not the final word. Revelation is the book-length development of this verse's eschatological confidence.</p>",
    "17": "<p><b>Theme.</b> <em>Discipline your son, and he will give you rest; he will give delight to your heart</em> — the rest and delight of the well-formed child. Matthew 11:28-30: <em>come to me, all who labor and are heavy laden, and I will give you rest</em>. Christ gives rest to those who have been formed under his gentle discipline — his yoke is easy, his burden light, the rest is genuine. The Father's delight in the well-formed Son was declared at baptism and transfiguration; those being formed into Christ's image give the Father the same delight through their progressive conformity to the Son (Rom 8:29).</p>",
    "18": "<p><b>Direct / Type.</b> <em>Where there is no prophetic vision, the people are unrestrained; but blessed is he who keeps the law</em> — prophetic vision as the ordering principle of community life. The Word became flesh (John 1:14) — the vision restored: <em>we have seen his glory</em>. Hebrews 1:1-2: <em>long ago, at many times and in many ways, God spoke... but in these last days he has spoken to us by his Son</em>. Christ is the chazon (vision/prophetic word) in person — not an oracle transmitted through a prophet but the Prophet himself (Deut 18:15; Acts 3:22). The community ordered by his word has the vision that keeps it from dissolving into unrestrained chaos. The beatitude for the law-keeper closes the verse: those who keep his word are blessed (John 14:21, 23).</p>",
    "19": "<p><b>Theme.</b> <em>By mere words a servant is not disciplined, for though he understands, he will not respond</em> — the limits of verbal instruction without accompanying change. The parable of the two sons (Matt 21:28-32): the son who said <em>I will not</em> and then went is preferred to the one who said <em>I will</em> and did not. Moral formation requires more than verbal compliance — the tax collectors and prostitutes who went ahead of the religious leaders into the kingdom were those who responded not merely verbally but behaviorally to John's call. Christ's formation of disciples includes works, signs, suffering, and commission — not merely teaching.</p>",
    "20": "<p><b>Theme.</b> <em>Do you see a man who is hasty in his words? There is more hope for a fool than for him</em> — impetuousness in speech as more resistant to correction than simple foolishness. Peter before the high priest's servant-girl (Matt 26:69-75) is the paradigmatic hasty-speech failure: thrice denying before he had considered what he was doing, then weeping bitterly when he recognized the pattern. But Christ's post-resurrection restoration of Peter (John 21:15-19) demonstrates that even the hasty-tongue has hope — Christ does not abandon the impetuous disciple but restores and commissions him. The proverb's diagnosis of the problem does not foreclose Christ's remedy.</p>",
    "21": "<p><b>Theme.</b> <em>Whoever pampers his servant from childhood will in the end find him to be his heir</em> — the indulged servant who overturns the master-servant structure. The disciples' recurring disputes about greatness (Matt 18:1; 20:20-24; Luke 22:24) are the temptation this proverb warns against — the servants who expected master-status. Christ's response inverts the expectation: <em>the greatest among you shall be your servant</em> (Matt 23:11). The one who makes himself a servant — as Christ did (Phil 2:7: <em>taking the form of a servant</em>) — is the one honored with the inheritance, not the servant who leverages indulgence into lordship.</p>",
    "22": "<p><b>Theme.</b> <em>A man of wrath stirs up strife, and one given to anger causes much transgression</em> — anger as a cascade-trigger. The brothers of James and John asked for fire to be called down on the Samaritan village (Luke 9:54-55); Christ rebuked them — the anger-strife-transgression cascade is exactly what he prevented. His instruction in Matthew 5:21-22 extends the prohibition deeper: anger itself, not just its outward expressions, is the seed of the murder-transgression chain. The new-heart work of the Spirit (Ezek 36:26) is what interrupts the cascade at its source.</p>",
    "23": "<p><b>Direct.</b> <em>One's pride will bring him low, but he who is lowly in spirit will obtain honor</em> — the humiliation-exaltation reversal. Philippians 2:8-9: <em>he humbled himself by becoming obedient to the point of death... therefore God has highly exalted him and bestowed on him the name that is above every name</em>. Christ is not merely the teacher of this principle but its enactment at cosmic scale — the one brought lowest of all is the one most highly honored. Luke 14:11; 18:14 are Christ's own citations of this principle as the governing logic of the kingdom's social order, which he first demonstrated in his own person.</p>",
    "24": "<p><b>Theme.</b> <em>The partner of a thief hates his own life; he hears the curse but discloses nothing</em> — the complicit silence that brings the curse upon the silent one. The disciples who fled at Christ's arrest (Matt 26:56) and Peter who denied him were partners in the silence of abandonment — not thievery, but the silent complicity that brought its own form of inner curse. The difference is what follows: genuine repentance (Peter's weeping) vs. despairing complicity (Judas's self-destruction). Christ's post-resurrection restoration demonstrates that the silence of complicity does not have to end in permanent self-destruction.</p>",
    "25": "<p><b>Direct.</b> <em>The fear of man lays a snare, but whoever trusts in the LORD is kept safe</em> — fear of man as the alternative to trusting God. Christ's commission directly addresses this: <em>do not fear those who kill the body but cannot kill the soul. Rather fear him who can destroy both soul and body in hell</em> (Matt 10:28). The snare of human fear is dissolved by proper fear of God — a fear that Christ reframes as trust in the Father who counts the very hairs of your head (Matt 10:30-31). Those who trust in the LORD are kept safe not from death but through it: <em>whoever loses his life for my sake will find it</em> (Matt 10:39).</p>",
    "26": "<p><b>Revelation of God.</b> <em>Many seek the face of a ruler, but it is from the LORD that a man gets justice</em> — the divine source of justice vs. the court-access system. Christ as the divine judge who gives true justice: <em>there is one lawgiver and judge, he who is able to save and to destroy</em> (Jas 4:12). The disciples were warned not to trust in courts for ultimate vindication: <em>when they deliver you over, do not be anxious how you are to speak, for it is not you who speak, but the Spirit of your Father speaking through you</em> (Matt 10:19-20). The one whose face they need to seek is not the human ruler but the Lord who gives justice.</p>",
    "27": "<p><b>Revelation of God.</b> <em>An unjust man is an abomination to the righteous, and one whose way is straight is an abomination to the wicked</em> — mutual abomination between righteousness and wickedness. The division Christ brings: <em>do not think that I have come to bring peace to the earth. I have not come to bring peace, but a sword</em> (Matt 10:34). The sword is precisely this mutual-abomination — the alignment of people with truth or with falsehood creates incompatibility that divides households. John 3:19-20: those who love darkness hate the light and do not come to it. The proverb's mutual abomination is the structural reality that Christ's coming makes explicit and unavoidable.</p>"
  },
  "30": {
    "1": "<p><b>Theme.</b> <em>The words of Agur son of Jakeh</em> — an unknown sage, possibly from the tribe of Massa (north Arabian). The wisdom tradition in Proverbs is explicitly international — Egyptian (22:17-24:22), and here possibly Arabian. Christ as the Wisdom of God (1 Cor 1:24; Col 2:3) is the fulfillment toward which all wisdom traditions grope, regardless of national origin. Paul on the Areopagus (Acts 17:27) argues that all nations, in their searching, are seeking the God who is <em>not far from each one of us</em> — Agur's wisdom-searching is a type of this universal groping toward the one who can be found.</p>",
    "2": "<p><b>Theme.</b> <em>Surely I am too stupid to be a man; I have not the understanding of a man</em> — Agur's confessional self-deprecation. The disciples' repeated failures to understand (Mark 9:32: <em>they did not understand the saying, and were afraid to ask him</em>) are the NT form of this honest incomprehension. But Paul extends it further: <em>the natural person does not accept the things of the Spirit of God, for they are folly to him, and he is not able to understand them because they are spiritually discerned</em> (1 Cor 2:14). The confession of inability that Agur models is the first movement of the wisdom the Spirit gives.</p>",
    "3": "<p><b>Theme.</b> <em>I have not learned wisdom, nor have I knowledge of the Holy One</em> — the acknowledged gap that sets up the questions of verse 4. Paul: <em>for now I know in part; then I shall know fully, even as I have been fully known</em> (1 Cor 13:12). The partial knowledge Agur acknowledges is the condition of all pre-resurrection wisdom. Christ is the one who gives the knowledge of the Holy One: <em>no one knows the Father except the Son and anyone to whom the Son chooses to reveal him</em> (Matt 11:27). The gap Agur confesses is precisely what the incarnation closes.</p>",
    "4": "<p><b>Direct.</b> <em>Who has ascended to heaven and come down? Who has gathered the wind in his fists? What is his name, and what is his son's name? Surely you know!</em> — the cosmological questions culminating in the question about the divine Son's name. Christ answers directly: <em>no one has ascended into heaven except he who descended from heaven, the Son of Man</em> (John 3:13). The name Agur could not supply — the Son's name — is given in the annunciation: <em>you shall call his name Jesus</em> (Matt 1:21). The gathering of wind (Job 38:31-33; Ps 104:4) and the wrapping of waters are the creative acts Colossians attributes to Christ (Col 1:16-17: <em>all things were created through him and for him... and in him all things hold together</em>). Agur's unanswerable question is the OT's most direct anticipation of the Father-Son revelation.</p>",
    "5": "<p><b>Direct.</b> <em>Every word of God proves true; he is a shield to those who take refuge in him</em> — the proven-true divine word as protective shield. Christ: <em>heaven and earth will pass away, but my words will not pass away</em> (Matt 24:35). His words are the proved-true, refined-silver speech of the perfectly reliable God. John 17:17: <em>your word is truth</em> — Christ's prayer is that his disciples be sanctified in the truth of this reliable word. And he himself is the Word (John 1:1) — the proved-true word is not merely a propositional claim but a person in whom the reliability of God is incarnated and demonstrated.</p>",
    "6": "<p><b>Theme.</b> <em>Do not add to his words, lest he rebuke you and you be found a liar</em> — the warning against supplementing the divine word. Revelation closes with the same warning (Rev 22:18-19) — the canonical boundary is preserved at the beginning and end of the biblical era. Christ fulfilled the law and the prophets (Matt 5:17) rather than supplementing them — the completion he brought was not addition but fulfillment. The tradition that made void the word of God (Mark 7:13) is the specific form of addition Christ condemned — human supplements that displaced rather than fulfilled.</p>",
    "7": "<p><b>Theme.</b> <em>Two things I ask of you; deny them not to me before I die</em> — the death-aware petition that frames the request of verses 8-9. Christ's Gethsemane prayer is the ultimate pre-death petition: <em>nevertheless, not my will but yours be done</em> (Luke 22:42). Agur's two requests are addressed to God with the explicit awareness of mortality; Christ's prayer is the absolute surrender of the one who faces death in full awareness of its reality. The petitioner who prays <em>before I die</em> anticipates the one whose death becomes the foundation of all subsequent petition.</p>",
    "8": "<p><b>Direct.</b> <em>Remove far from me falsehood and lying; give me neither poverty nor riches; feed me with the food that is needful for me</em> — the petition for the exactly-right portion. The Lord's Prayer: <em>give us this day our daily bread</em> (Matt 6:11). Agur's <em>lechem chukki</em> (food of my appointed portion) is the precise OT equivalent of the <em>epiousios</em> (daily/appointed) bread of the Lord's Prayer. Both prayers request exactly what is needed for today — neither accumulation nor deprivation — from the Father who knows what his children need before they ask (Matt 6:8). The Lord's Prayer is the Christological form of Agur's petition.</p>",
    "9": "<p><b>Theme.</b> <em>Lest I be full and deny you... or lest I be poor and steal and profane the name of my God</em> — the twin dangers of abundance and scarcity for covenant faithfulness. The Deuteronomic warning (Deut 8:10-14) is applied here with acute precision: fullness produces forgetfulness; deprivation produces the desperate act that desecrates the Name. Christ's instruction on anxiety (Matt 6:25-34) addresses both dangers: the one who trusts the Father neither gorges in abundance nor steals from desperation, because the Father's provision is secured for those who seek his kingdom. The Name is not profaned by those who live from the Father's hand.</p>",
    "10": "<p><b>Revelation of God.</b> <em>Do not slander a servant to his master, lest he curse you and you be held guilty</em> — the moral weight of the unjustly accused servant's curse. Christ as the servant unjustly accused (Isa 53:3-4: <em>despised and rejected... we esteemed him stricken, smitten by God, and afflicted, but he was pierced for our transgressions</em>). The false accusations brought against him at his trial carried moral weight — those who brought them were <em>held guilty</em> in the precise sense this proverb describes. Peter's Pentecost sermon: <em>you crucified and killed by the hands of lawless men</em> (Acts 2:23) — the slander held its accusers guilty.</p>",
    "11": "<p><b>Theme.</b> <em>There are those who curse their fathers and do not bless their mothers</em> — fifth commandment violation as the seed of all the moral failures in the catalogue (verses 11-14). Christ's summary of the law with the neighbor-love command (Matt 22:34-40) is grounded in the vertical relationship with God — the one who does not honor the Father cannot keep any of the other commands. The specific parent-cursing failure is a sign of a disordered relationship with authority itself — which is why Christ saw the Pharisees' Corban rule (Mark 7:9-13) not merely as a legal technicality but as the symptom of a heart that had displaced God.</p>",
    "12": "<p><b>Revelation of God.</b> <em>There are those who are pure in their own eyes but are not washed of their filth</em> — the self-assessed purity that is actually defilement. Christ's diagnosis: <em>unless one is born of water and the Spirit, he cannot enter the kingdom of God</em> (John 3:5). The washing that removes actual filth is not self-generated; it is the washing of regeneration (Titus 3:5). The Pharisees who were pure in their own eyes are the clearest NT expression of this proverb — the whitewashed tombs (Matt 23:27) clean on the outside, defiled within. The only adequate washing is Christ's atoning blood and the Spirit's renewal.</p>",
    "13": "<p><b>Theme.</b> <em>There are those — how lofty are their eyes, how high their eyelids lift!</em> — embodied pride. Christ's observation about the Pharisees who loved the place of honor at feasts and the chief seats in the synagogues (Matt 23:6) is the social form of the lofty eye. The beatitude that counters it: <em>blessed are the poor in spirit</em> (Matt 5:3) — the lowered eyes of genuine poverty-of-spirit is the posture of the kingdom. The lofty eye before God (Prov 6:17) is the abomination that the cross definitively addresses: the cross is the place where all human loftiness is stripped away and the truth of human need is exposed.</p>",
    "14": "<p><b>Theme.</b> <em>There are those whose teeth are swords... to devour the poor from off the earth</em> — predatory consumption of the poor. The rich man who feasted sumptuously while Lazarus lay at his gate (Luke 16:19-21) is the devouring of the poor that this proverb indicts. The reversal in the parable (Luke 16:25) is Proverbs 30:14's verdict enacted: those who consumed the poor find themselves in want while the devoured Lazarus is comforted. Isaiah's indictment of those who <em>grind the faces of the poor</em> (Isa 3:15) and Amos 8:4 (<em>you trample on the needy and bring the poor of the land to an end</em>) are the prophetic developments of the same observation.</p>",
    "15": "<p><b>Theme.</b> <em>The leech has two daughters: Give, Give. Three things are never satisfied; four never say, Enough</em> — insatiability as a category. The spiritual hunger that drives human restlessness is addressed by Christ: <em>everyone who drinks of this water will be thirsty again, but whoever drinks of the water that I will give him will never be thirsty again</em> (John 4:13-14). The never-satisfied categories Agur identifies — Sheol, the barren womb, the thirsty earth, fire — find their satisfaction-resolution only in eschatology (Rev 21:4: <em>death shall be no more</em>) and in the living water that Christ gives as the foretaste of that final satisfaction.</p>",
    "16": "<p><b>Theme.</b> <em>Sheol, the barren womb, the land never satisfied with water, and the fire that never says Enough</em> — the four insatiable things: death, infertility, drought, fire. Christ's resurrection addresses the first directly: <em>death is swallowed up in victory</em> (1 Cor 15:54). The barren womb made fruitful is a recurring resurrection-motif (Elizabeth, Luke 1:36). The living water Christ gives satisfies the parched earth of the soul (John 7:38-39). The fire that is satisfied — the Spirit as fire at Pentecost (Acts 2:3) brings the holy consuming fire that purifies without demanding more. Each insatiable thing finds its resolution in Christ's redemptive work.</p>",
    "17": "<p><b>Theme.</b> <em>The eye that mocks a father and scorns to obey a mother will be picked out by ravens of the valley</em> — filial contempt's graphic consequence. The soldiers who mocked Christ at the cross (Matt 27:27-31) — the contemptuous eye directed at the Father's beloved Son — is the NT form of this parental-dishonoring. The ravens picking out the eye is the unburied-corpse image of the ultimate shame. But the resurrection reverses the shame: the one whose eyes were mocked became the one before whom every eye shall see (Rev 1:7) — <em>every eye will see him, even those who pierced him</em>.</p>",
    "18": "<p><b>Theme.</b> <em>Three things are too wonderful for me; four I do not understand: the way of an eagle, a serpent on a rock, a ship at sea, and the way of a man with a virgin</em> — the four pathways that leave no trace. The mysteries of movement through their media without residue. The incarnation is the greatest wonder of all: the eternal Word taking a way through the virgin's womb (Matt 1:20-23; Luke 1:35) — the way of a man with a virgin being the form of the miracle that Agur could only observe as wonder. <em>Behold, the virgin shall conceive and bear a son</em> (Isa 7:14; Matt 1:23) is the divine entering through the path Agur identified as unfathomable.</p>",
    "19": "<p><b>Theme.</b> <em>The way of an eagle in the heavens</em> — the wonder of purposeful movement whose path is invisible. Isaiah 40:31: <em>they who wait for the LORD shall renew their strength; they shall mount up with wings like eagles</em>. The ascension of Christ (Acts 1:9-11: <em>as they were looking on, he was lifted up, and a cloud took him out of their sight</em>) is the ultimate eagle-way — the ascent through the heavens that left no visible path but opened the way for the Spirit to descend. The disciples were to wait in Jerusalem for what the invisible path had made possible (Acts 1:4).</p>",
    "20": "<p><b>Revelation of God.</b> <em>This is the way of an adulteress: she eats and wipes her mouth and says, I have done no wrong</em> — the self-exonerated moral evasion. The religious leaders who declared <em>if we had lived in the days of our fathers, we would not have taken part with them in shedding the prophets' blood</em> (Matt 23:30) are the adulteress of this verse — wiping their mouths and declaring innocence while continuing the same pattern. Christ's response: <em>you witness against yourselves</em> (Matt 23:31). The self-exoneration that Proverbs identifies as the adulteress's character is the defining mark of those who reject Christ while claiming to honor God.</p>",
    "21": "<p><b>Revelation of God.</b> <em>Under three things the earth trembles; under four it cannot bear up</em> — the cosmic-weight of social disorder. Matthew 27:51: at the death of the righteous one, the earth shook (<em>kai he ge eseisthe</em>), tombs were opened. The earth-trembling that Proverbs assigns to social inversions finds its maximum expression at the crucifixion — the one moment when all four of Agur's inversions are simultaneously in play: the wicked are ruling, justice is inverted, the blameless is being destroyed. The earth cannot bear it and shakes. The resurrection is the restoration of order that the earth's trembling demanded.</p>",
    "22": "<p><b>Theme.</b> <em>A servant when he reigns, and a fool when he is filled with food</em> — two of the earth-trembling social inversions. The disciples' dispute about greatness (Luke 22:24-27) brings Jesus's definitive teaching: <em>the kings of the Gentiles exercise lordship over them... but not so with you. Rather, let the greatest among you become as the youngest, and the leader as one who serves</em>. The servant who reigns without having been formed for it is the disaster Proverbs describes; the servant who is given authority through the formation of service (as Christ modeled) is the kingdom's pattern of leadership.</p>",
    "23": "<p><b>Theme.</b> <em>An unloved woman when she gets a husband, and a maidservant when she displaces her mistress</em> — domestic inversions with cosmic weight. The Magnificat (Luke 1:46-55) is the theological response to both: <em>he has brought down the mighty from their thrones and exalted those of humble estate; he has filled the hungry with good things and the rich he has sent away empty</em>. Mary's song is the announcement that in Christ, the earth-trembling inversions Agur catalogues are themselves about to be inverted — the low are exalted, the proud are scattered. The order is restored not by preventing the inversions but by Christ's own redeeming work.</p>",
    "24": "<p><b>Theme.</b> <em>Four things on earth are small, but they are exceedingly wise</em> — wisdom exceeding size. Christ's parables consistently feature the small-as-paradigm: the mustard seed that becomes a great tree (Matt 13:31-32), the leaven hidden in three measures of flour (Matt 13:33), the lost coin (Luke 15:8-10). The kingdom of God is the small-and-wise thing that operates by principles opposite to worldly power-measurement. <em>God chose what is weak in the world to shame the strong</em> (1 Cor 1:27) — the cross itself is the ultimate small-and-wise thing that confounds the wisdom of the world.</p>",
    "25": "<p><b>Theme.</b> <em>The ants are a people not strong, yet they provide their food in the summer</em> — cooperative provision despite weakness. The early Jerusalem church (Acts 2:44-45; 4:32-35) embodied the ant-wisdom: <em>all who believed were together and had all things in common... there was not a needy person among them</em>. The community without worldly strength providing for all its members is the social form of ant-wisdom. Christ's feeding of the multitude multiplied the five loaves and two fish — the small provision of the weak, entrusted to Christ, became more than sufficient.</p>",
    "26": "<p><b>Theme.</b> <em>The rock badgers are a people not mighty, yet they make their homes in the cliffs</em> — finding security through knowledge of environment rather than through strength. Peter's confession (Matt 16:18: <em>you are the Christ, the Son of the living God... and on this rock I will build my church</em>) is the cliffs-for-the-weak made concrete: the weakness of the disciples' position is secured not by their strength but by the Rock — Christ himself. The rock badger who cannot fight but makes its home in inaccessible cliffs is the disciple community that has no worldly power but is established on the indestructible foundation.</p>",
    "27": "<p><b>Theme.</b> <em>The locusts have no king, yet all of them march in rank</em> — self-organizing order without a visible center. The post-resurrection community in Acts operates without a visible human king (Jesus is ascended) yet maintains coherent direction through the Spirit. Acts 4:32: <em>the full number of those who believed were of one heart and soul</em> — the locust-march without a visible king is the Spirit-directed community that moves with coordinated purpose because its king is present invisibly. The ascension created precisely this condition: the king is gone from sight but the community marches.</p>",
    "28": "<p><b>Theme.</b> <em>The lizard you can take in your hands, yet it is in kings' palaces</em> — access through adaptability. Christ's ministry penetrated every social level: he ate with tax collectors and sinners (Matt 9:10-11), healed Jairus's daughter (a synagogue ruler, Mark 5:22), and commended the faith of a Roman centurion (Matt 8:10). The gospel itself is the lizard that entered kings' palaces — Paul before Felix, Festus, and Agrippa (Acts 24-26); the gospel reaching Caesar's household (Phil 4:22). The small, apparently vulnerable thing that cannot be kept out of the highest spaces is the gospel itself.</p>",
    "29": "<p><b>Theme.</b> <em>Three things are stately in their tread; four are stately in their stride: the lion, the rooster, the he-goat, and a king whose army is with him</em> — stately movement as the mark of legitimate authority. Christ's triumphal entry (Matt 21:5, citing Zech 9:9: <em>behold, your king is coming to you, humble and mounted on a donkey</em>) is the stately stride reframed. He enters with the composed dignity of the lion-king — not with military display but with the purposive unhurried movement of one who has authority. Revelation 19:11-16 shows the eschatological form: the rider on the white horse whose armies follow him — the king with his army in their ultimate stately march.</p>",
    "30": "<p><b>Type.</b> <em>The lion, which is mightiest among beasts and does not turn back before any</em> — the lion's fearless authority as the paradigm of legitimate power. Christ is the Lion of the tribe of Judah (Rev 5:5) who overcomes — the mightiest who does not turn back before any adversary. The paradox of Revelation 5 is that this Lion is also the Lamb who was slain — the fearless advance toward the cross is the lion's stride that did not turn back before death, Hades, or the powers of darkness. <em>He who is in you is greater than he who is in the world</em> (1 John 4:4).</p>",
    "31": "<p><b>Theme.</b> <em>The strutting rooster, the he-goat, and a king whose army is with him</em> — the intermediate and climactic members of the stately-stride catalogue. The he-goat as leader of the flock (Jer 50:8; Zech 10:3) is a messianic figure in the prophets — the leader-goat going before the flock. Christ is the shepherd who goes ahead of his sheep (John 10:4: <em>he goes before them, and the sheep follow him, for they know his voice</em>). The king with his army echoes Revelation 19:14 (<em>the armies of heaven, arrayed in fine linen, white and pure, were following him</em>) — the ultimate stately march of the king and his redeemed army.</p>",
    "32": "<p><b>Theme.</b> <em>If you have been foolish, exalting yourself, or if you have been devising evil, put your hand on your mouth</em> — the gesture of self-silencing as the beginning of repentance. Job's response to God's speeches from the whirlwind (Job 40:4: <em>behold, I am of small account; what shall I answer you? I lay my hand on my mouth</em>) is the paradigmatic hand-on-mouth. The disciples' silence in the presence of Christ's glory at the transfiguration (Matt 17:6: <em>when the disciples heard this, they fell on their faces and were terrified</em>) is the NT form — the appropriate silencing of human self-exaltation before the divine presence. Christ's parable: <em>everyone who exalts himself will be humbled</em> (Luke 14:11).</p>",
    "33": "<p><b>Revelation of God.</b> <em>For pressing milk produces curds, pressing the nose produces blood, and pressing anger produces strife</em> — cause-and-effect at multiple levels. Christ's diagnosis of the heart's cause-and-effect is the deepest form of this principle: <em>out of the abundance of the heart the mouth speaks</em> (Matt 12:34). What is pressed out of the heart determines the outcome — the pressing of the self-controlled heart (which has received Christ's peace, John 14:27) produces peace rather than strife. Paul's instruction: <em>do not be overcome by evil, but overcome evil with good</em> (Rom 12:21) — the pressing of good overcomes the pressing of anger. Agur's final word is wisdom about mechanism — Christ addresses the heart that drives the mechanism.</p>"
  }
}

def main():
    e = load_comm('mkt-christ', 'proverbs')
    merge_comm(e, DATA)
    save_comm('mkt-christ', 'proverbs', e)
    count = sum(len(v) for v in DATA.values())
    print(f'proverbs mkt-christ: wrote {count} verses across ch 28-30')

if __name__ == '__main__':
    main()
